import React, { useState, useRef } from 'react';
import '../assets/styles/Keyboard_mouse.css'; // Importăm fișierul CSS separat

const Keyboard_mouse = () => {
  const [startTouch, setStartTouch] = useState(null);  // Punctul de început al atingerii
  const [isClick, setIsClick] = useState(true);  // Stare pentru a detecta dacă e un click simplu sau mișcare
  const [inputText, setInputText] = useState('');  // Textul tastat
  const sensitivity = 2.7;  // Factorul de sensibilitate pentru mișcarea cursorului
  const inputRef = useRef(null);  // Referință pentru câmpul de input

  let dynamicThrottleLimit = 100; // Inițial throttle-ul este setat la 100ms, dar îl vom ajusta dinamic

  // Funcție de throttling pentru a limita cât de des trimitem date la server
  const throttle = (func, limit) => {
    let lastFunc;
    let lastRan;
    return (...args) => {
      if (!lastRan) {
        func(...args);
        lastRan = Date.now();
      } else {
        clearTimeout(lastFunc);
        lastFunc = setTimeout(() => {
          if ((Date.now() - lastRan) >= limit) {
            func(...args);
            lastRan = Date.now();
          }
        }, limit - (Date.now() - lastRan));
      }
    };
  };

  // Funcție pentru obținerea CSRF token-ului
  const getCookie = (name) => {
    let cookieValue = null;
    if (document.cookie && document.cookie !== '') {
      const cookies = document.cookie.split(';');
      for (let i = 0; i < cookies.length; i++) {
        const cookie = cookies[i].trim();
        if (cookie.substring(0, name.length + 1) === (name + '=')) {
          cookieValue = decodeURIComponent(cookie.substring(name.length + 1));
          break;
        }
      }
    }
    return cookieValue;
  };

  const csrftoken = getCookie('csrftoken');  // Obține token-ul CSRF din cookie-uri

  // Trimite coordonatele relative către server pentru a muta cursorul
  const sendMouseMove = (deltaX, deltaY) => {
    fetch('/shortcuts/keyboard_mouse/move_mouse/', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-CSRFToken': csrftoken,  // Adăugăm tokenul CSRF la cerere
      },
      body: JSON.stringify({ action: 'move', x: deltaX, y: deltaY })
    }).catch(error => console.error('Error:', error));
  };

  // Aplicați throttling funcției sendMouseMove cu limită dinamică
  const throttledMouseMove = throttle(sendMouseMove, dynamicThrottleLimit);

  const handleTouchStart = (event) => {
    const touch = event.touches[0];
    // Salvăm poziția inițială unde degetul atinge touchpad-ul
    setStartTouch({ x: touch.clientX, y: touch.clientY });
    setIsClick(true);  // La începutul atingerii, presupunem că e un click
  };

  const handleTouchMove = (event) => {
    event.preventDefault();
    const touch = event.touches[0];

    if (startTouch) {
      // Calculăm diferența de mișcare relativă față de poziția inițială și aplicăm factorul de sensibilitate
      const deltaX = (touch.clientX - startTouch.x) * sensitivity;
      const deltaY = (touch.clientY - startTouch.y) * sensitivity;

      // Dacă utilizatorul mișcă degetul, nu mai e un click
      if (Math.abs(deltaX) > 5 || Math.abs(deltaY) > 5) {
        setIsClick(false);  // Dacă delta este semnificativă, e o mișcare, nu un click
      }

      // Adjustăm throttling-ul în funcție de viteză (distanța mișcării)
      const movementMagnitude = Math.sqrt(deltaX * deltaX + deltaY * deltaY);
      if (movementMagnitude < 10) {
        // Dacă mișcarea este foarte mică, trimitem cereri mai rar (300ms)
        dynamicThrottleLimit = 1000;
      } else if (movementMagnitude < 50) {
        // Mișcare moderată - throttling la 150ms
        dynamicThrottleLimit = 850;
      } else {
        // Mișcare rapidă - throttling la 50ms
        dynamicThrottleLimit = 450;
      }

      // Trimitem mișcarea cu throttling pentru a evita supraîncărcarea cererilor
      throttledMouseMove(deltaX, deltaY);

      // Actualizăm punctul de start pentru a continua mișcarea relativă
      setStartTouch({ x: touch.clientX, y: touch.clientY });
    }
  };

  const handleTouchEnd = () => {
    if (isClick) {
      // Dacă nu a fost detectată mișcare semnificativă, trimitem un click stânga simplu
      handleClick('left');
    }
    // Resetăm punctul de start când utilizatorul ridică degetul
    setStartTouch(null);
  };

  // Trimite o cerere POST pentru a face click (stânga, dreapta sau dublu click)
  const handleClick = (button = 'left', double = false) => {
    fetch('/shortcuts/keyboard_mouse/move_mouse/', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-CSRFToken': csrftoken,  // Asigură-te că tokenul CSRF este adăugat
      },
      body: JSON.stringify({ action: 'click', button: button, double: double })
    }).catch(error => console.error('Error:', error));
  };

  // Funcție care se ocupă de trimiterea input-ului tastat la server
  const sendKeyboardInput = (text) => {
    console.log(`Sending key: ${text}`);  // Debugging
    fetch('/shortcuts/keyboard_mouse/keyboard_input/', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-CSRFToken': csrftoken,  // Asigură-te că tokenul CSRF este adăugat
      },
      body: JSON.stringify({ key: text })
    }).then(response => response.json())
      .then(data => console.log('Success:', data))
      .catch(error => console.error('Error:', error));
  };

  // Funcție care se activează când utilizatorul apasă pe butonul de deschidere a tastaturii
  const openKeyboard = () => {
    inputRef.current.focus();  // Focalizează câmpul de text pentru a deschide tastatura
  };

  // Eveniment care capturează textul tastat și îl trimite la server
  const handleInputChange = (event) => {
    const newText = event.target.value;
  
    // Detectăm ștergerea și trimitem 'Backspace' sau 'Delete' în funcție de caz
    if (event.nativeEvent.inputType === 'deleteContentBackward') {
      sendKeyboardInput('Backspace');  // Trimite Backspace pentru fiecare apăsare de Backspace
    } else if (event.nativeEvent.inputType === 'deleteContentForward') {
      sendKeyboardInput('Delete');  // Trimite Delete pentru ștergere de la dreapta la stânga
    } else if (newText.length > inputText.length) {
      const lastChar = newText[newText.length - 1]; // Obținem ultimul caracter tastat
      if (lastChar === '\n') {
        sendKeyboardInput('Enter');  // Trimitem Enter ca tasta specială
      } else {
        sendKeyboardInput(lastChar);  // Trimitem doar ultimul caracter tastat
      }
    }
  
    // Actualizăm textul doar în scopuri de UI
    setInputText(newText);
  };
  

  const handleRightClick = (event) => {
    event.preventDefault(); // Previne comportamentul default pentru click dreapta
    handleClick('right');
  };

  const handleDoubleClick = () => {
    handleClick('left', true); // Dublu click pe click stânga
  };

  return (
    <div>
      <div
        className="touchpad-container"
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
        onContextMenu={handleRightClick}  // Captură pentru click dreapta
        onDoubleClick={handleDoubleClick}  // Captură pentru dublu click
      >
        <h2>Touchpad Controller</h2>
        <p>Use the touchpad to move the mouse and tap to click.</p>
        <p>Right-click by long-pressing or double-tap for double-click.</p>
      </div>

      <button onClick={openKeyboard}>Open Keyboard</button>
      <input
        ref={inputRef}
        type="text"
        value={inputText}
        onChange={handleInputChange}
        style={{ opacity: 0, position: 'absolute', left: '-9999px' }}  // Ascundem câmpul de input
      />
    </div>
  );
};

export default Keyboard_mouse;
